// ==============================================
// Code after AI Agent (упрощенный, БЕЗ прогресса)
// ==============================================

// 1. Ответ от AI Agent
const aiResponse = $node["AI Agent"].json.output;

// 2. Фиксированный chatId
const chatId = 1126144455;

// 3. Если это учебный план
if (typeof aiResponse === 'string' && aiResponse.includes('Тема') && aiResponse.includes('[')) {
  console.log("✅ Обнаружен учебный план");

  // Парсим количество тем (для внутреннего учета)
  const lines = aiResponse.split('\n');
  let topicCount = 0;

  for (const line of lines) {
    if (line.includes('Тема') && line.includes('[')) {
      topicCount++;
    }
  }

  console.log(`AI предложил ${topicCount} тем`);

  // Сохраняем только факт создания плана
  const staticData = $workflow.staticData || {};
  staticData[chatId] = {
    planCreated: true,
    plan: aiResponse, // Сохраняем весь план как текст
    completedPosts: [], // Пустой массив для учета
    createdAt: new Date().toISOString()
  };
  $workflow.staticData = staticData;

  // Первое понятие - всегда "переменные" для теста
  const firstConcept = "переменные";

  return {
    json: {
      needsTavily: true,
      tavilyQuery: "Python variables basics",
      originalData: {
        chatId: chatId,
        currentConcept: firstConcept
      }
    }
  };
}

// 4. Если это запрос к Tavily
if (typeof aiResponse === 'string' && aiResponse.includes('tavily(query="')) {
  const match = aiResponse.match(/tavily\(query="([^"]+)"\)/);
  if (match) {
    // Просто передаем запрос дальше
    return {
      json: {
        needsTavily: true,
        tavilyQuery: match[1],
        originalData: {
          chatId: chatId,
          currentConcept: extractConceptFromQuery(match[1])
        }
      }
    };
  }
}

// 5. Просто текст
return {
  json: {
    needsTavily: false,
    messageText: aiResponse
  }
};

function extractConceptFromQuery(query) {
  // Просто возвращаем первое слово для учета
  return query.split(' ')[0] || "программирование";
}

// Мы в ветке IF → FALSE
// Значит интернет не нужен, просто возвращаем текст от AI Agent

const input = $json;

// Рекурсивно ищем текст в любом месте JSON
function findText(obj) {
  if (typeof obj === 'string') return obj;

  if (Array.isArray(obj)) {
    for (const i of obj) {
      const t = findText(i);
      if (t) return t;
    }
  }

  if (typeof obj === 'object' && obj !== null) {
    for (const k of Object.keys(obj)) {
      const t = findText(obj[k]);
      if (t) return t;
    }
  }

  return null;
}

const text = findText(input) || 'Пустой ответ от AI Agent';

// Возвращаем стабильно в поле text
return [{
  text
}];

// ==============================================
// Code: Передача данных с фиксированным chatId
// ==============================================

// 1. Получаем результаты от HTTP Request
const tavilyData = $input.item.json;

// 2. Фиксированный chatId
const chatId = 5779648277;

// 3. Получаем originalData из первой ноды Code
let originalData = {};
let currentConcept = "переменные";

try {
  const codeData = $node["Code in JavaScript"].json;
  if (codeData.originalData) {
    originalData = codeData.originalData;
    currentConcept = originalData.currentConcept || "переменные";
    console.log("✅ Получен originalData");
  }
} catch (error) {
  console.log("Не удалось получить originalData, используем фиксированные значения");
}

// 4. Объединяем данные с фиксированным chatId
return [{
  json: {
    // Данные для AI Agent
    query: tavilyData.query,
    results: tavilyData.results,
    answer: tavilyData.answer,

    // Передаем с фиксированным chatId
    originalData: {
      chatId: chatId, // Фиксированный ID
      currentConcept: currentConcept,
      plan: originalData.plan || [],
      isFirstPost: originalData.isFirstPost || false
    }
  }
}];

// ==============================================
// Code: Учет пройденных понятий (БЕЗ прогресса)
// ==============================================

// 1. Фиксированный chatId
const chatId = 5779648277;

// 2. Получаем пост от AI Agent
const aiPost = $input.item.json.output;

// 3. Получаем currentConcept
let currentConcept = "переменные";
if ($input.item.json.originalData && $input.item.json.originalData.currentConcept) {
  currentConcept = $input.item.json.originalData.currentConcept;
}

// 4. Работаем с Static Data
let staticData = $workflow.staticData || {};

// 5. Получаем или создаем состояние пользователя
if (!staticData[chatId]) {
  staticData[chatId] = {
    plan: [],
    completedPosts: [], // ТОЛЬКО ЭТО НУЖНО ДЛЯ УЧЕТА
    currentConcept: currentConcept
  };
}

const userState = staticData[chatId];

// 6. ВЕДЕМ УЧЕТ (основное требование задания)
// Добавляем понятие в пройденные, если еще нет
if (!userState.completedPosts.includes(currentConcept)) {
  userState.completedPosts.push(currentConcept);
  console.log(`✅ Учет: добавлено понятие "${currentConcept}"`);
  console.log(`Всего пройдено: ${userState.completedPosts.length} понятий`);
}

// 7. Обновляем Static Data
$workflow.staticData = staticData;

// 8. Просто возвращаем пост без прогресса
return {
  json: {
    chatId: chatId,
    messageText: aiPost // Чистый пост без добавок
  }
};
